INSERT INTO `contact_messages` (`id`, `nom`, `email`, `sujet`, `message`, `statut`, `date_envoi`, `date_lecture`, `ip_address`, `deleted_at`) VALUES
(9, 'Thomat Leroy', 'thomas.leroy@outlook.fr', 'question', 'Bonjour,\r\nJe suis actuellement étudiant en informatique et je m’intéresse beaucoup aux projets de robotique présentés sur votre site.\r\nJ’aimerais savoir s’il est possible de participer aux activités du Fablab en tant qu’étudiant externe, ou s’il faut obligatoirement être inscrit à AJC Formation.\r\n\r\nMerci d’avance pour votre retour.', 'traite', '2026-02-01 18:54:13', '2026-03-18 17:24:44', '::1', NULL),
(10, 'Sophie Nguyen', 'sophie.nguyen@orange.com', 'feedback', 'Bonjour,\r\nNous avons découvert votre Fablab dans le cadre d’une veille sur les initiatives de formation en technologies numériques.\r\nLes projets sont très inspirants et reflètent un bon niveau technique. Nous serions intéressés par une éventuelle collaboration ou intervention auprès de vos apprenants.\r\n\r\nCordialement,\r\nSophie Nguyen\r\nResponsable innovation chez : TechSolutions', 'lu', '2026-02-01 18:55:39', '2026-03-05 13:46:18', '::1', NULL),
(11, 'Julien Moreau', 'julien.moreau@gmail.com', 'question', 'Bonjour,\r\nJe souhaite me reconvertir dans le domaine du développement web et de la robotique. Votre Fablab m’a été recommandé par un ancien apprenant.\r\nPourriez-vous m’indiquer si des journées portes ouvertes ou des démonstrations sont prévues prochainement ?\r\n\r\nMerci pour votre temps.. !', 'lu', '2026-02-01 18:57:22', '2026-02-12 14:48:00', '::1', NULL),
