INSERT INTO `projects` (`id`, `title`, `description`, `description_detailed`, `technologies`, `image_url`, `features`, `challenges`, `categorie`, `created_at`, `updated_at`, `deleted_at`, `auteur_id`) VALUES
(1, 'Robot Tout-Terrain 6 Roues', 'Robot mobile autonome à 6 roues motrices pour navigation sur terrains difficiles.', 'Plateforme robotique robuste équipée de 6 roues tout-terrain avec jantes rouges. Architecture à châssis blanc avec système de suspension indépendante. Le robot intègre un module de contrôle central avec capteur ultrasonique bleu pour la détection d\'obstacles. Conçu pour des missions d\'exploration en extérieur et capable de franchir des obstacles variés grâce à sa configuration 6x6.', 'Châssis 6WD, Moteurs DC avec encodeurs, Arduino/ESP32, Capteur ultrasonique HC-SR04, Pont en H L298N, Batterie LiPo, Structure imprimée 3D', 'image_projet1.png', 'Configuration 6 roues motrices|Suspension indépendante|Détection d\'obstacles ultrasonique|Châssis modulaire imprimé 3D|Haute mobilité tout-terrain|Grande capacité de charge|Alimentation autonome LiPo', 'Synchronisation des 6 moteurs pour une trajectoire rectiligne, gestion de la puissance pour maintenir l\'autonomie avec 6 moteurs actifs, et optimisation du système de suspension pour différents types de terrains.', 'Mécanique', '2024-01-15 10:00:00', '2026-03-09 19:16:00', NULL, 5),
(2, 'Robot Autonome avec Écran LCD', 'Robot mobile intelligent avec système de navigation autonome et interface LCD.', 'Robot compact équipé d\'un écran LCD 20x4 pour affichage en temps réel des données de navigation. Le système intègre des capteurs ultrasoniques montés sur servo-moteur pour balayage panoramique, permettant une détection d\'obstacles à 360°. Châssis rouge imprimé en 3D avec 4 roues motrices. Interface utilisateur complète avec boutons de contrôle et affichage des modes de fonctionnement, distances mesurées et statut du robot.', 'Arduino Uno/Mega, Écran LCD 20x4 I2C, Capteurs ultrasoniques HC-SR04, Servo-moteur pour balayage, Moteurs DC, Pont en H, Boutons de navigation', 'image_projet2.png', 'Écran LCD 20x4 informatif|Balayage ultrasonique 360°|Navigation autonome intelligente|Interface utilisateur avec boutons|Affichage temps réel des distances|Modes de fonctionnement multiples|Châssis compact imprimé 3D', 'Intégration de l\'affichage LCD sans ralentir la boucle de contrôle principale, algorithme de décision pour choisir la meilleure direction selon les obstacles détectés, et gestion de l\'espace limité pour tous les composants.', 'Impression 3D', '2024-02-01 14:30:00', '2026-03-09 17:58:30', NULL, 5),
(3, 'Robot Multi-Capteurs Avancé', 'Plateforme robotique avancée avec système de capteurs multiples et traitement complexe.', 'Robot sophistiqué intégrant plusieurs types de capteurs pour une perception environnementale complète. Architecture ouverte montrant Arduino Mega, modules de capteurs ultrasoniques, capteur de ligne au sol, et système de câblage organisé. Châssis rouge transparent permettant une visibilité complète des composants électroniques. Idéal pour l\'apprentissage de la robotique avancée et le prototypage de systèmes autonomes complexes.', 'Arduino Mega 2560, Capteurs ultrasoniques multiples, Capteur de ligne IR, Module Bluetooth HC-05, Pont en H double, Encodeurs de roues, Châssis acrylique', 'image_projet3.png', 'Architecture modulaire ouverte|Multiples capteurs ultrasoniques|Suivi de ligne au sol|Contrôle Bluetooth|Encodeurs pour odométrie|Câblage organisé et accessible|Plateforme éducative complète', 'Gestion de multiples flux de données capteurs simultanés, synchronisation des différents modules de perception, et optimisation du code pour éviter les ralentissements avec l\'Arduino Mega.', 'Robotique', '2023-11-10 09:15:00', '2026-02-18 11:26:57', NULL, 5),
(4, 'Station IoT Raspberry Pi', 'Centre de contrôle IoT basé sur Raspberry Pi pour monitoring et automation.', 'Station de développement et de contrôle IoT construite autour d\'un Raspberry Pi 4. Le système comprend plusieurs modules connectés : caméra pour vision artificielle, module GPS, capteurs environnementaux et interfaces de communication. Boîtier rouge imprimé 3D avec tous les ports accessibles. Cette station sert de hub central pour collecter, traiter et transmettre des données depuis divers capteurs distribués dans l\'espace du Fablab.', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'image_projet4.png', 'Processing puissant Raspberry Pi 4|Vision artificielle avec caméra|Géolocalisation GPS|Connectivité WiFi et Ethernet|Interface web de monitoring|Communication MQTT|Boîtier modulaire personnalisé', 'Configuration optimale des services système pour démarrage automatique, gestion de la sécurité réseau pour l\'accès à distance, et optimisation de la consommation pour un fonctionnement 24/7.', 'Impression 3D', '2023-11-10 16:45:00', '2026-03-06 15:11:11', NULL, 5),
(5, 'Drone FPV Racing Personnalisé', 'Quadricoptère FPV pour course de drones avec frame personnalisée.', 'Station de développement et de contrôle IoT construite autour d\'un Raspberry Pi 4. Le système comprend plusieurs modules connectés : caméra pour vision artificielle, module GPS, capteurs environnementaux et interfaces de communication. Boîtier rouge imprimé 3D avec tous les ports accessibles. Cette station sert de hub central pour collecter, traiter et transmettre des données depuis divers capteurs distribués dans l\'espace du Fablab.', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'image_projet5.png', 'Processing puissant Raspberry Pi 4|Vision artificielle avec caméra|Géolocalisation GPS|Connectivité WiFi et Ethernet|Interface web de monitoring|Communication MQTT|Boîtier modulaire personnalisé', 'Configuration optimale des services système pour démarrage automatique, gestion de la sécurité réseau pour l\'accès à distance, et optimisation de la consommation pour un fonctionnement 24/7.', 'Drone / FPV', '2024-03-20 08:30:00', '2026-03-11 17:50:39', NULL, 5),
