(49, 'Un projet concret : le robot suiveur de ligne', 'sdsdsdsdsdsds', 'sdssdsdsdsd', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'https://cdn8.futura-sciences.com/a1280/images/Boston-Dynamics-Atlas.jpg', 'sdsssssssss', 'sddddddddddddd', 'Programmation', '2026-03-16 13:55:28', '2026-03-18 14:02:04', '2026-03-18 14:02:04', 5),
(50, 'Un projet concret : le robot suiveur de ligne', 'sdsdsdsdsdsdsdsd', 'sdsdsdsdsdsdsdsdsdsdsdsdsdsdsdsd', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'https://cdn8.futura-sciences.com/a1280/images/Boston-Dynamics-Atlas.jpg', 'aaaaaa', 'sdsdsdsdsdsdsdsd', 'Drone / FPV', '2026-03-16 14:00:01', '2026-03-18 14:02:02', '2026-03-18 14:02:02', 5),
(51, 'Robot mobile autonome de surveillance', 'Robot capable de patrouiller dans un espace et détecter des anomalies.', 'Ce projet consiste à concevoir un robot mobile équipé de capteurs de distance et d’une caméra embarquée. L’objectif est de développer un système autonome capable de circuler dans un environnement intérieur et d’identifier des obstacles ou mouvements inhabituels.\r\n\r\nLe robot utilise une logique de navigation basée sur la détection d’obstacles et la cartographie simplifiée. Une interface web permet de visualiser en temps réel les données collectées et d’intervenir à distance si nécessaire.', 'Arduino, capteurs ultrasons, JavaScript, AJAX', 'https://static.generation-robots.com/img/robotnik-rb-watcher-xl.jpg', 'patrouille autonome, détection d’obstacles, transmission des données, visualisation en temps réel, contrôle à distance', 'calibration des capteurs, stabilité des déplacements, gestion de l’autonomie, synchronisation entre le robot et l’interface web', 'Robotique', '2026-03-18 14:05:04', '2026-03-18 14:05:04', NULL, 5),
(52, 'Robot suiveur de ligne intelligent', 'Robot pédagogique capable de suivre un circuit tracé au sol.', 'Ce projet a pour objectif de développer un robot capable de détecter une ligne noire sur fond clair à l’aide de capteurs infrarouges. Les différents tests ont permis d’ajuster la vitesse, la précision des virages et la stabilité globale du robot afin d’obtenir un déplacement fluide.', 'Arduino, C embarqué, capteurs infrarouges, moteurs DC', 'https://sti.eduscol.education.fr/system/files/images/ressources/pedagogiques/14706/14706-robot-suiveur-de-ligne-01.jpg', 'détection de ligne, correction automatique de trajectoire, réglage de vitesse, suivi de parcours, arrêt de sécurité', 'sensibilité des capteurs, précision dans les virages, variations de lumière, équilibrage des moteurs', 'Robotique', '2026-03-18 14:06:22', '2026-03-18 14:06:22', NULL, 5),
(53, 'Bras robotisé programmable', 'Bras robotisé permettant d’automatiser des tâches simples.', 'Ce projet consiste à réaliser un bras robotisé contrôlé par servomoteurs afin d’exécuter des mouvements précis. Il permet de découvrir la programmation des articulations, la gestion des angles et la reproduction de séquences de mouvements.', 'Raspberry Pi, Python, servomoteurs, interface web', 'https://cdn.xingosoftware.com/elektor/images/fetch/dpr_1,w_800,h_460,c_fit/https%3A%2F%2Fwww.elektormagazine.fr%2Fassets%2Fupload%2Fimages%2F17%2F220232-006-94-original-6-dof-robot-arm-holding-frontjpg.png', 'contrôle des articulations, enregistrement de mouvements,exécution de séquences, pilotage manuel, interface de commande', 'précision des mouvements, limitation mécanique des axes, alimentation des servomoteurs, coordination des articulations', 'Robotique', '2026-03-18 14:07:36', '2026-03-18 14:07:36', NULL, 5),
(54, 'Station météo connectée', 'Dispositif capable de mesurer les conditions climatiques en temps réel.', 'Ce projet consiste à créer une station météo capable de relever plusieurs mesures environnementales et de les transmettre à une interface web. L’objectif est de combiner capteurs, électronique embarquée et affichage dynamique des données.', 'ESP32, DHT22, capteur de pression, API REST, JavaScript', 'https://encrypted-tbn1.gstatic.com/shopping?q=tbn:ANd9GcROqiJOWAgrsg_EtvHNasq-cSua9bh82p54o9NFBPC56PRgL8UI73BpSrvciGmc1OrhLFVTOzRVROIGsQRxAygGP2AOBVKmRiV2dsRIWvY&usqp=CAc', 'mesure de température, mesure d’humidité, relevé de pression, envoi des données, affichage graphique', 'fiabilité des relevés, stabilité de la connexion, fréquence d’actualisation, gestion des erreurs capteurs', 'Électronique', '2026-03-18 14:08:48', '2026-03-18 14:08:48', NULL, 5),
(55, 'Système d’éclairage intelligent', 'Gestion automatique de l’éclairage selon la luminosité ambiante.', 'Le projet consiste à développer un système capable d’allumer ou d’éteindre automatiquement un éclairage selon la lumière détectée dans l’environnement. Il s’inscrit dans une logique de domotique et d’automatisation.', 'Arduino, capteur LDR, relais, LED', 'https://cdn.webshopapp.com/shops/71227/files/445517354/eclairage-intelligent-decouvrez-les-avantages-et.jpg', 'détection de luminosité, activation automatique, désactivation automatique, seuil réglable, affichage de l’état', 'réglage du seuil lumineux, sensibilité du capteur, stabilité du circuit, tests en conditions réelles', 'Électronique', '2026-03-18 14:09:58', '2026-03-18 14:09:58', NULL, 5),
(56, 'Carte électronique prototype modulaire', 'Création d’une carte électronique personnalisée pour projets embarqués.', 'Ce projet vise à concevoir une carte électronique modulaire facilitant l’intégration de plusieurs composants dans différents prototypes. Elle permet d’améliorer la maintenabilité, l’organisation du câblage et la réutilisation de certains modules.', 'KiCad, composants électroniques, soudure, microcontrôleur', 'https://www.elsys-design.com/wp-content/uploads/2019/07/prototypage-carte-produit-industriel.jpg', 'intégration modulaire, support de composants, alimentation centralisée, connecteurs réutilisables, prototypage rapide', 'conception du schéma, qualité des soudures, correction des erreurs de câblage, optimisation de l’espace sur la carte', 'Électronique', '2026-03-18 14:10:59', '2026-03-18 14:10:59', NULL, 5),
(57, 'Dashboard web de pilotage robotique', 'Interface web permettant de contrôler un robot à distance.', 'Ce projet consiste à développer un tableau de bord web permettant d’envoyer des commandes à un robot et de suivre ses informations en temps réel. Il met en avant la communication entre une interface front-end et un système embarqué.', 'PHP MVC, JavaScript, Fetch API, AJAX, MySQL', 'https://cdn.dribbble.com/userupload/43737610/file/original-4b1ba715dcb221f828ab624c5aed3435.png?resize=752x&vertical=center', 'envoi de commandes, affichage temps réel, tableau de bord interactif, remontée d’état, interface responsive', 'communication temps réel, gestion des requêtes asynchrones, fiabilité des données, ergonomie de l’interface', 'Programmation', '2026-03-18 14:11:56', '2026-03-18 14:11:56', NULL, 5),
(58, 'API interne de gestion des projets', 'Création d’un système d’API pour structurer les échanges de données.', 'Le projet a pour but de créer une API interne afin de centraliser certaines opérations de lecture et de mise à jour des données. Cette architecture facilite la communication entre le back-end et des interfaces dynamiques plus modernes.', 'PHP, JSON, MVC, MySQL', 'https://www.colmar.tech/wp-content/uploads/2025/10/Guide-complet-pour-comprendre-et-utiliser-les-API-dans-vos-projets.jpg', 'récupération des données, envoi de réponses JSON, filtrage des résultats, mise à jour dynamique, intégration front-end', 'récupération des données, envoi de réponses JSON, filtrage des résultats, mise à jour dynamique, intégration front-end', 'Programmation', '2026-03-18 14:13:14', '2026-03-18 14:13:14', NULL, 5),
(59, 'Système de pagination dynamique', 'Optimisation du chargement des contenus volumineux.', 'Ce projet met en place une pagination dynamique afin de limiter le nombre d’éléments chargés simultanément et d’améliorer l’expérience utilisateur. Il s’applique à des listes de projets, articles ou vidéos volumineuses.', 'AJAX, JavaScript, PHP, SQL optimisé', 'https://developer.mozilla.org/en-US/docs/Web/CSS/How_to/Layout_cookbook/Pagination/pagination.png', 'chargement progressif, navigation paginée, mise à jour sans rechargement, optimisation des requêtes, meilleure performance', 'calcul des pages, synchronisation front/back, optimisation SQL, maintien d’une navigation fluide', 'Programmation', '2026-03-18 14:14:36', '2026-03-18 14:14:36', NULL, 5),
(60, 'Conception d’un châssis robotique imprimé en 3D', 'Fabrication d’un châssis léger et modulable pour robot mobile.', 'Ce projet vise à concevoir et imprimer un châssis robotique adapté à différents types de robots pédagogiques. Les participants utilisent un logiciel de modélisation 3D pour créer une structure optimisée, puis testent plusieurs impressions afin d’améliorer la résistance et la stabilité.', 'Fusion 360, imprimante 3D FDM, PLA', 'https://www.weerg.com/hs-fs/hubfs/berkeley-humaonid-lite.png?width=800&height=464&name=berkeley-humaonid-lite.png', 'support des composants électroniques, structure modulable, fixation des moteurs, optimisation du poids, adaptation des dimensions', 'support des composants électroniques, structure modulable, fixation des moteurs, optimisation du poids, adaptation des dimensions', 'Impression 3D', '2026-03-18 14:15:38', '2026-03-18 14:15:38', NULL, 5),
(61, 'Fabrication de supports de capteurs personnalisés', 'Création de supports adaptés aux capteurs robotiques.', 'Ce projet consiste à concevoir des supports spécifiques permettant de positionner correctement différents capteurs sur un robot. Les apprenants testent plusieurs designs afin d’améliorer la précision des mesures.', 'Tinkercad, impression 3D, prototypage rapide', 'https://image.lsrpf.com/image/cnc-machining-vibration-control-mounts-stainless-steel-industrial.jpg', 'fixation des capteurs, ajustement des angles, compatibilité multi-robots, installation rapide, personnalisation des modèles', 'tolérances mécaniques, précision dimensionnelle, solidité des fixations, optimisation du design', 'Impression 3D', '2026-03-18 14:16:40', '2026-03-18 14:16:40', NULL, 5),
(62, 'Prototypage rapide d’un boîtier électronique', 'Création d’un boîtier de protection pour cartes électroniques.', 'L’objectif de ce projet est de concevoir un boîtier sur mesure permettant de protéger les composants électroniques tout en facilitant l’accès aux ports et aux câbles. Plusieurs versions sont testées afin d’améliorer l’ergonomie.', 'robot,cable,fil,connexion internet, wifi, capteur sonore,vision', 'https://www.captronic.fr/IMG/arton4114.png?1714995799', 'protection des composants, ventilation intégrée, accès aux connecteurs, montage rapide, design personnalisé', 'dissipation thermique, précision des ouvertures, solidité du boîtier, compatibilité avec les cartes', 'Impression 3D', '2026-03-18 14:17:35', '2026-03-18 14:29:38', NULL, 5),
(63, 'Système de transmission par engrenages', 'Étude et réalisation d’un mécanisme de transmission robotique.', 'Ce projet permet d’analyser le fonctionnement des engrenages et leur impact sur la vitesse et le couple d’un robot. Les participants conçoivent différents systèmes mécaniques afin d’optimiser les performances de déplacement.', 'modélisation mécanique, impression 3D, assemblage', 'https://i.ytimg.com/vi/f_LRf3taMOc/maxresdefault.jpg', 'transmission du mouvement, réduction de vitesse, augmentation du couple, adaptation des rapports, test de performance', 'usure des pièces, alignement des axes, friction mécanique, précision d’assemblage', 'Mécanique', '2026-03-18 14:19:16', '2026-03-18 14:19:16', NULL, 5),
(64, 'Conception d’un système de suspension robotique', 'Amélioration de la stabilité d’un robot mobile.', 'Ce projet consiste à intégrer un système de suspension permettant d’absorber les irrégularités du terrain. Les tests réalisés permettent d’optimiser la mobilité du robot sur différentes surfaces.', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'https://spaceflightnow.com/news/n1205/10rovertest/15.jpg', 'absorption des chocs, amélioration de la stabilité, adaptation au terrain, optimisation des déplacements, réduction des vibrations', 'réglage de la rigidité, intégration dans le châssis, équilibrage du robot, contraintes d’espace', 'Mécanique', '2026-03-18 14:20:21', '2026-03-18 14:28:19', NULL, 5),
(65, 'Optimisation du centre de gravité d’un robot', 'Étude de l’équilibrage pour améliorer la mobilité.', 'Les participants analysent la répartition des masses sur un robot afin d’optimiser sa stabilité et ses performances. Plusieurs configurations sont testées pour identifier la meilleure disposition des composants.', 'prototypage mécanique, tests dynamiques', 'https://sciencepost.fr/wp-content/uploads/2025/09/7-1440x1080-1.jpg', 'équilibrage du robot, amélioration de la traction, optimisation de la stabilité, analyse des performances, ajustement des composants', 'répartition des charges, contraintes de design, adaptation aux moteurs, tests en conditions réelles', 'Mécanique', '2026-03-18 14:21:17', '2026-03-18 14:21:17', NULL, 5),
(66, 'Conception et pilotage d’un drone FPV', 'Conception et pilotage d’un drone FPV', 'Ce projet consiste à concevoir un drone FPV (First Person View) destiné à des expérimentations pédagogiques en robotique et en pilotage immersif. L’objectif est de comprendre les principes de stabilisation, de transmission vidéo en temps réel et de contrôle à distance.\r\n\r\nLes participants travaillent sur l’intégration des différents composants : châssis léger, moteurs brushless, contrôleur de vol et système de caméra embarquée. Une phase de tests permet d’optimiser les réglages afin d’obtenir un vol stable et réactif.\r\n\r\nCe projet permet d’aborder des notions avancées telles que la gestion des fréquences radio, l’équilibrage des hélices et la sécurisation du pilotage dans un environnement contrôlé.', 'contrôleur de vol, moteurs brushless, transmission vidéo FPV, batterie LiPo', 'https://cdn2.sculpteo.com/blog/wp-content/uploads/2017/11/222-min.jpg', 'pilotage immersif en temps réel, stabilisation automatique, transmission vidéo directe, réglage de la vitesse, mode sécurité', 'réglage des paramètres de vol, autonomie limitée de la batterie, gestion des interférences radio, stabilité lors des phases d’accélération', 'Drone / FPV', '2026-03-18 14:23:12', '2026-03-18 14:23:12', NULL, 5),
(67, 'Drone FPV autonome avec suivi GPS', 'Drone capable de suivre un itinéraire prédéfini grâce à un module GPS intégré.', 'Ce projet consiste à développer un drone FPV capable d’effectuer des vols semi-autonomes en suivant des coordonnées GPS programmées à l’avance. L’objectif pédagogique est de comprendre le fonctionnement des systèmes de géolocalisation et leur intégration dans des projets robotiques.\r\n\r\nLes participants travaillent sur la calibration du module GPS, la gestion de la stabilité en vol et l’optimisation des trajectoires. Une interface permet également de visualiser la position du drone en temps réel.\r\n\r\nCe projet permet d’aborder des notions avancées comme la navigation assistée, l’optimisation énergétique et la sécurité des systèmes autonomes.', 'contrôleur de vol, module GPS, firmware Betaflight, transmission FPV', 'https://enterprise-insights.dji.com/hs-fs/hubfs/PFD%202.png?width=714&name=PFD%202.png', 'suivi d’itinéraire GPS, stabilisation automatique, retour position de vol, pilotage manuel assisté, visualisation temps réel', 'précision du signal GPS, dérive de trajectoire, gestion de l’autonomie, calibration des capteurs', 'Drone / FPV', '2026-03-18 14:24:51', '2026-03-18 14:24:51', NULL, 5),
(68, 'Drone FPV pour captation vidéo immersive', 'Drone destiné à la réalisation de prises de vues dynamiques en immersion.', 'Ce projet vise à concevoir un drone FPV optimisé pour la captation vidéo immersive lors d’événements ou de démonstrations pédagogiques. Le drone est équipé d’une caméra stabilisée permettant d’obtenir des images fluides même lors de déplacements rapides.\r\n\r\nLes apprenants expérimentent différents réglages moteurs et angles de caméra afin d’améliorer la qualité des images et la précision du pilotage.\r\n\r\nCe projet met en avant l’utilisation des drones dans des contextes professionnels comme la communication digitale ou la production audiovisuelle.', 'caméra HD embarquée, moteurs brushless, contrôleur de vol, batterie LiPo', 'https://www.neural-drone.com/wp-content/uploads/2025/04/P1000700-scaled-e1745401424176.jpg', 'captation vidéo immersive, transmission en direct, réglage angle caméra, stabilisation de vol, pilotage précis', 'vibrations en vol, qualité du signal vidéo, gestion de la vitesse, sécurité lors des manœuvres', 'Drone / FPV', '2026-03-18 14:25:57', '2026-03-18 15:24:08', NULL, 5),
(69, 'Un projet concret : le robot suiveur de ligne', 'dsfsfdsfsdfsdfsdf', 'dsfsfdsfsdfsdfsdfdsfsfdsfsdfsdfsdf', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'https://images.ctfassets.net/hrltx12pl8hq/28ECAQiPJZ78hxatLTa7Ts/2f695d869736ae3b0de3e56ceaca3958/free-nature-images.jpg?fit=fill&w=1200&h=630', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'qdsdsdsdqdsdsdsdqdsdsdsdqdsdsdsd', 'Programmation', '2026-03-20 09:35:57', '2026-03-20 09:35:57', NULL, 5),
(70, 'Un projet concret : le robot suiveur de ligne', 'sfsdfdsfsdfdsfsdfdsfsdfd', 'sfsdfdsfsdfdsfsdfd', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'https://images.ctfassets.net/hrltx12pl8hq/28ECAQiPJZ78hxatLTa7Ts/2f695d869736ae3b0de3e56ceaca3958/free-nature-images.jpg?fit=fill&w=1200&h=630', 'Raspberry Pi 4, Caméra Pi v2, Module GPS, Capteurs I2C multiples, WiFi/Ethernet, Python, Node-RED, MQTT', 'ffqsdfsdfsdfsdfdsfdsfsdfsdfsdf', 'Électronique', '2026-03-20 10:36:36', '2026-03-20 11:03:53', NULL, 19);
