(3, 'Introduction au Fablab', 'Présentation générale du FabLab et de ses projets innovants en robotique..', 'Présentation', 'youtube', '', 'https://www.youtube.com/watch?v=x8Pc9hqTEO8', 'https://img.youtube.com/vi/x8Pc9hqTEO8/hqdefault.jpg', 199, NULL, 5, 0, '2025-12-12 21:54:33', NULL),
(4, 'Présentation site internet WEB TV FR OFFICIEL', 'Projet étudiant création de site web afin de mettre en avant différents contenus liées au fablab interne de l\'entreprise', 'Demonstration', 'youtube', '', 'https://www.youtube.com/watch?v=mSyo25hKnfo', 'https://img.youtube.com/vi/mSyo25hKnfo/hqdefault.jpg', 19, NULL, 5, 0, '2025-12-12 21:54:33', NULL),
(5, 'Comment créer sa propre Web TV : Tout ce qu\'il faut savoir !!', 'Techniques de création dédié à un programme classique non evolutif : multi agent', 'Tutoriel', 'youtube', '', 'https://www.youtube.com/watch?v=Ikownb7GSjE', 'https://img.youtube.com/vi/Ikownb7GSjE/hqdefault.jpg', 5, NULL, 5, 0, '2025-12-12 21:54:33', NULL),
(6, 'Atelier Robotique', 'Démonstration robotique et présentation des projets étudiants associés.', 'Tutoriel', 'youtube', '', 'https://www.youtube.com/watch?v=msY6LTbBc2s', 'https://img.youtube.com/vi/msY6LTbBc2s/hqdefault.jpg', 5, NULL, 5, 0, '2025-12-12 21:54:33', NULL),
(26, 'Un projet concret : le robot suiveur de ligne', 'qddsqdqsdqsdqdsqdsq', 'Demonstration', 'youtube', '', 'https://www.youtube.com/watch?v=U3AzJO0nZ6o', 'https://img.youtube.com/vi/U3AzJO0nZ6o/hqdefault.jpg', 0, NULL, 19, 0, '2026-03-09 08:27:35', '2026-03-09 09:35:51'),
(30, 'Les 30 nouveaux robots de 2025 qui sont d\'un autre niveau !', 'Ils battent déjà des records sportifs, nous émerveillent par leurs capacités et s\'envolent dans l\'espace ! Il semble donc que le moment soit venu de mieux les connaître. Prêts à découvrir comment les robots les plus révolutionnaires de la planète sont en train de changer le monde à jamais ? Alors restez avec nous !', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=5hGOWJ5HSNY', 'https://img.youtube.com/vi/5hGOWJ5HSNY/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:46:38', NULL),
(31, 'Les nouveaux robots IA chinois bluffent tout le monde avec leurs compétences incroyables', 'Découvrez les robots humanoïdes qui dansent, font du kung-fu et réalisent des acrobaties dignes des plus grands films ! Entre démos techniques, performances télévisées et innovations venues de Chine, UK et USA, plongez dans le futur de la robotique.', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=_v563IkLOb0', 'https://img.youtube.com/vi/_v563IkLOb0/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:47:17', NULL),
(32, '14 robots parmi les plus avancés capables d\'effectuer des actions complexes [Robots humanoïdes', 'Découvrez des robots de pointe réalisant des actions complexes de manière autonome, grâce à l\'intelligence artificielle. Cette vidéo vous présente des robots humanoïdes capables de marcher, courir, sauter, exprimer des émotions humaines et collaborer avec les humains. Vous verrez également des chiens robots, des robots-oiseaux, etc.', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=mf2rvZ7Uv4s', 'https://img.youtube.com/vi/mf2rvZ7Uv4s/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:47:54', NULL),
(33, 'Hyundai présente son robot Atlas de nouvelle génération au CES 2026', 'Découvrez la présentation par Hyundai Motor Group et Boston Dynamics de leur robot Atlas 100 % électrique de nouvelle génération, conçu pour les travaux en usine.', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=9e0SQn9uUlw', 'https://img.youtube.com/vi/9e0SQn9uUlw/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:48:30', NULL),
(34, 'Air Spot | Recherche comportementale en RL | Boston Dynamics', 'Nous examinons de plus près les mécanismes du développement de nouveaux comportements avec Spot grâce à la recherche en apprentissage par renforcement, et pourquoi repousser les limites du matériel grâce à des prouesses sportives contribue à créer de meilleurs robots pour nos clients.', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=LMPxtcEgtds', 'https://img.youtube.com/vi/LMPxtcEgtds/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:48:56', NULL),
(35, 'Dynamic Whole-Body Manipulation with Spot', 'Le robot Spot effectue des manipulations dynamiques de l\'ensemble du corps grâce à une combinaison d\'apprentissage par renforcement et de contrôle par échantillonnage. Son comportement, visible dans la vidéo, est entièrement autonome : il gère la sélection dynamique des points de contact sur les bras, les jambes et le corps, et coordonne les processus de manipulation et de locomotion.', 'Robotique', 'youtube', '', 'https://www.youtube.com/watch?v=nM_ZHzp8nQA', 'https://img.youtube.com/vi/nM_ZHzp8nQA/hqdefault.jpg', 1, NULL, 5, 0, '2026-03-18 16:49:52', NULL),
(36, 'Débuter en impression 3D (le guide simple)', 'Tuto simple pour débutant !', 'Impression 3D', 'youtube', '', 'https://www.youtube.com/watch?v=pQw6Y1bOWiU', 'https://img.youtube.com/vi/pQw6Y1bOWiU/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:52:21', NULL),
(37, 'Le guide ULTIME pour l\'impression 3D', 'Vous venez d\'acheter une imprimante 3D et votre tête est remplie de question ? C\'est normal, vous débutez ! C\'est LA vidéo que vous devez voir pour bien comprendre comment fonctionnent les bases de votre imprimante 3D.', 'Impression 3D', 'youtube', '', 'https://www.youtube.com/watch?v=nrZqbeBN3xc&t=53s', 'https://img.youtube.com/vi/nrZqbeBN3xc/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:53:15', NULL),
(38, 'Comment fonctionne une imprimante 3D ?', 'Découverte en profondeur de la consistance réelle du 3D et datacentré', 'Impression 3D', 'youtube', '', 'https://www.youtube.com/watch?v=f94CnlQ0eq4', 'https://img.youtube.com/vi/f94CnlQ0eq4/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:54:12', NULL),
(39, 'Guide du débutant en imprimantes 3D en 2023', 'Ce guide du débutant sur les imprimantes 3D vous explique ce à quoi vous devez vous attendre pour débuter avec les imprimantes 3D en 2023 ! Voici un aperçu des connaissances essentielles pour vous lancer dans l’impression 3D.', 'Impression 3D', 'youtube', '', 'https://www.youtube.com/watch?v=m12bX1eEVDM', 'https://img.youtube.com/vi/m12bX1eEVDM/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:55:38', NULL),
(40, 'Fabriquez un petit drone Arduino avec une caméra FPV - volera-t-il?', 'Dans ce didacticiel passionnant, nous plongeons dans le monde des micro-drones en fabriquant un petit drone Arduino FPV (First Person View) brossé entièrement à partir de bâtons de glace. Apprenez à installer et configurer votre mini quadricoptère à l\'aide du code Arduino et du logiciel MultiWii pour un contrôle de vol personnalisable. Vivez le frisson des vols agiles et à grande vitesse en intérieur et en extérieur !', 'Projet', 'youtube', '', 'https://www.youtube.com/watch?v=Sa6EslOHsI0', 'https://img.youtube.com/vi/Sa6EslOHsI0/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:56:28', NULL),
(41, 'Fabrication de Petit Robot qui Explore les surfaces', 'Dans ce projet, j\'ai construit un petit robot de bureau appelé Mo-chan \r\n\r\nUn petit compagnon qui explore son environnement, se dandine doucement sur votre bureau et peut également être contrôlé via Wi-Fi à l\'aide de votre téléphone.', 'Projet', 'youtube', '', 'https://www.youtube.com/watch?v=3hjvpyjxPsk', 'https://img.youtube.com/vi/3hjvpyjxPsk/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:57:34', NULL),
(42, 'J\'ai construit un robot auto-équilibré de A à Z (basé sur Arduino).', 'J\'ai conçu un robot auto-équilibré. Il est basé sur Arduino et imprimé en 3D sans aucun support ! Cette vidéo vous guidera à travers le processus de construction et certains des défis que je rencontre dans ce projet.', 'Projet', 'youtube', '', 'https://www.youtube.com/watch?v=K1lzzVGCzAQ', 'https://img.youtube.com/vi/K1lzzVGCzAQ/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:58:11', NULL),
(43, 'Comment fonctionnent les robots auto-équilibrés ! (Théorie, composants, conception, PID)', 'Circuit imprimé simple, abordable et fiable avec JLCPCB !', 'Projet', 'youtube', '', 'https://www.youtube.com/watch?v=J5Xd43LIFiU', 'https://img.youtube.com/vi/J5Xd43LIFiU/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 16:58:49', NULL),
(44, 'Run de Atlas 2000 en live !', 'Une première depuis une décennie : venez regarder cette incroyable vidéo.', 'Demonstration', 'youtube', '', 'https://www.youtube.com/watch?v=I44_zbEwz_w', 'https://img.youtube.com/vi/I44_zbEwz_w/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:00:00', NULL),
(45, 'Démonstration Atlas en parcours dangereux', 'Dans cette vidéo, nous pouvons constater l\'avancé technologiques du monde sur ces deux dernières années.', 'Demonstration', 'youtube', '', 'https://www.youtube.com/watch?v=tF4DML7FIWk', 'https://img.youtube.com/vi/tF4DML7FIWk/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:00:56', NULL),
(46, 'Demo : Les robots les plus avancés du monde !', 'Voici une liste des robots humanoïdes, industriels et de service les plus avancés qui révolutionnent l\'avenir grâce à l\'intelligence artificielle.', 'Demonstration', 'youtube', '', 'https://www.youtube.com/watch?v=Jky9I1ihAkg', 'https://img.youtube.com/vi/Jky9I1ihAkg/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:01:51', NULL),
(47, 'La tech mondiale dépend... de cette entreprise européenne', '149 612 vues  22 avr. 2025\r\nCapables de graver des transistors sur des composants avec une finesse de quelques nanomètres, les machines d’ASML sont les plus avancées pour la fabrication des semi-conducteurs. Elles assurent à cette société néerlandaise une domination mondiale sur ce secteur stratégique.', 'Electronique', 'youtube', '', 'https://www.youtube.com/watch?v=UO99e7_YCRo&pp=ygUcZWxlY3Ryb25pcXVlIHZpZGVvIGZyYW5jYWlzZQ%3D%3D', 'https://img.youtube.com/vi/UO99e7_YCRo/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:03:07', NULL),
(48, 'Le Transistor expliqué simplement – Le cœur de l’électronique moderne !', 'Dans cette vidéo, nous découvrons le fonctionnement d’un transistor. À travers des analogies simples et des schémas clairs, vous comprendrez :\r\n\r\nLe rôle de chaque broche (base, collecteur, émetteur)', 'Electronique', 'youtube', '', 'https://www.youtube.com/watch?v=NKS0ds06yVk', 'https://img.youtube.com/vi/NKS0ds06yVk/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:03:41', NULL),
(49, 'Les Transistors Expliqués - Comment Fonctionnent Les Transistors', 'Transistors, Comment fonctionnent les transistors. Dans cette vidéo, nous apprendrons comment fonctionnent les transistors, les différents types de transistors, les bases des circuits électroniques, comment construire un circuit à transistor, un amplificateur à transistor, un gain de courant bêta, npn, pnp, un dissipateur de chaleur, l\'électronique et l\'électrotechnique. Et bien plus encore!', 'Electronique', 'youtube', '', 'https://www.youtube.com/watch?v=Ey1nnEoADcg', 'https://img.youtube.com/vi/Ey1nnEoADcg/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:04:09', NULL),
(50, 'Conférence tech 2025', 'Dans cette vidéo, nous avons eu une avant-première sur les locaux/espaces retrouvés lors de la conférence mondiale des technologies divers et variés.', 'Evenement', 'youtube', '', 'https://www.youtube.com/watch?v=BOG_CbEDhag', 'https://img.youtube.com/vi/BOG_CbEDhag/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:06:11', NULL),
(51, 'Vidéo événement Blue tech', 'Cette vidéo raconte l\'événement Blue Tech qui a marqué plusieurs dizaines de générations.', 'Evenement', 'youtube', '', 'https://www.youtube.com/watch?v=V1nV8PM7878', 'https://img.youtube.com/vi/V1nV8PM7878/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:07:02', NULL),
(52, 'Réunion du conseil technologique', 'Dans cette vidéo, on peut retrouver l\'ensemble des nouvelles règles et mesures appliquées aux différentes technologies en vigueur.', 'Evenement', 'youtube', '', 'https://www.youtube.com/watch?v=N8tnM9KyLos', 'https://img.youtube.com/vi/N8tnM9KyLos/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:08:04', NULL),
(53, 'Une journée avec une mécanicienne automobile', 'Cette vidéo est en partenariat avec Renault. Renault est partenaire de lycées professionnels et de CFA qui proposent un bac pro classique auquel s\'ajoutent 10 jours de formation exclusifs Renault.', 'Mecanique', 'youtube', '', 'https://www.youtube.com/watch?v=DiUnzjf1R8o', 'https://img.youtube.com/vi/DiUnzjf1R8o/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:08:57', NULL),
(54, 'Comment fonctionne le moteur d\'une voiture ? - C\'est pas sorcier', 'Comment fonctionne le moteur d\'une voiture ? Jamy vous explique ! \r\nPour tout savoir sur les voitures de course', 'Mecanique', 'youtube', '', 'https://www.youtube.com/watch?v=5ziTd4Mv0cM', 'https://img.youtube.com/vi/5ziTd4Mv0cM/hqdefault.jpg', 1, NULL, 5, 0, '2026-03-18 17:09:27', NULL),
(55, 'Comment fonctionne une voiture ? Les bases de l’anatomie automobile (Animation 3D)', 'Dans cette vidéo, nous apprendrons comment fonctionne un véhicule, à travers l’exemple de la structure d’une voiture moderne.\r\nNous parlerons des principaux éléments et systèmes d’un automobile : la carrosserie, le châssis, le moteur, la transmission (chaîne cinématique), la suspension, ainsi que les équipements électriques et bien plus encore.', 'Mecanique', 'youtube', '', 'https://www.youtube.com/watch?v=VNPlolHJJMk', 'https://img.youtube.com/vi/VNPlolHJJMk/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:10:26', NULL),
(56, 'Un embrayage, comment ça marche ?', 'Vous êtes-vous déjà demandé ce qui se passe à l\'intérieur d\'une voiture quand vous appuyez sur la pédale d\'embrayage ? Ou encore, pourquoi faut-il appuyer sur la pédale d\'embrayage avant de changer de vitesse dans un véhicule à boîte manuelle ? Dans cette vidéo, vous trouverez des réponses concrètes à ces questions.', 'Mecanique', 'youtube', '', 'https://www.youtube.com/watch?v=mQVX-CIsFi0', 'https://img.youtube.com/vi/mQVX-CIsFi0/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-18 17:10:58', NULL),
(57, 'La Base De La Mécanique Pour Les Débutants. Moteur/Pneus/Niveaux Liquides', 'Dans cette vidéo, on peut retrouver notre interne qui détaille tous les processus et procédés en termes de motorisation.', 'Mecanique', 'youtube', '', 'https://www.youtube.com/watch?v=1lpkF3Sx9qI', 'https://img.youtube.com/vi/1lpkF3Sx9qI/hqdefault.jpg', 2, NULL, 5, 0, '2026-03-18 17:11:55', NULL),
(58, 'Un projet concret : le robot suiveur de ligne', 'qdsdsdsdqdsdsdsdqdsdsdsd', 'Atelier', 'youtube', '', 'https://www.youtube.com/watch?v=yR6C5RvtCIk&list=TLPQMTAwMjIwMjZ1ec685X-MQw&index=2', 'https://img.youtube.com/vi/yR6C5RvtCIk/hqdefault.jpg', 0, NULL, 5, 0, '2026-03-20 09:36:18', '2026-03-20 10:31:36'),
(59, 'Un projet concret : le robot suiveur de ligne', 'dfdfggfdgdfgdfgdfg', 'Programmation', 'youtube', '', 'https://www.youtube.com/watch?v=yR6C5RvtCIk&list=TLPQMTAwMjIwMjZ1ec685X-MQw&index=2', 'https://img.youtube.com/vi/yR6C5RvtCIk/hqdefault.jpg', 1, NULL, 19, 0, '2026-03-20 10:36:50', NULL);
